const peryshkin7Solutions: GdzProblem[] = [
  { number: '1', page: 5, condition: '1. Определите цену деления секундомера (см. рис. 10). 2. По рисункам 8 и 9 определите цену деления', steps: ['1 м = 10 дм = 100 см.', '9 м = 9 · 10 = 90 дм.', '9 м = 9 · 100 = 900 см.'], answer: '90 дм; 900 см.' },
  { number: '3', page: 6, condition: '1. Выразите скорости тел: 90 км/ч и 36 км/ч в м/c. 2. Поезд идёт со скоростью 72 км/ч. Выразите его', steps: ['1 км = 1000 м.', '1 г = 0,001 кг.', '1 л = 0,001 м³.'], answer: '1 км = 1000 м; 1 г = 0,001 кг; 1 л = 0,001 м³.' },
  { number: '5', page: 8, condition: '1. Встряхните медицинский термометр. Почему показание столбика ртути начинает падать? 2', steps: ['Формула скорости: v = s / t.', 'v = 20 м / 4 с = 5 м/с.'], formulas: ['v = s/t'], answer: '5 м/с.' },
  { number: '8', page: 11, condition: '1. Какова масса 0,5 л спирта, молока, ртути? 2. Определите объём льдинки, масса которой 108 г. 3', steps: ['Диффузия — самопроизвольное взаимное проникновение частиц одного вещества в другое.', 'Пример: запах духов распространяется по комнате.'], answer: 'Диффузия — проникновение молекул. Пример: запах духов.' },
  { number: '11', page: 13, condition: '1. Определите цену деления каждого прибора и силу тяжести, действующую на каждый груз (рис. 75)', steps: ['m = ρ · V.', 'ρ = 1 кг/дм³, V = 5 дм³.', 'm = 1 · 5 = 5 кг.'], formulas: ['m = ρV'], answer: '5 кг.' },
  { number: '15', page: 16, condition: '1. Рассмотрите устройство плоскогубцев и клещей (рис. 92). При помощи какого инструмента можно', steps: ['V = m / ρ.', 'V = 15,6 кг / 7800 кг/м³ = 0,002 м³ = 2 дм³.'], formulas: ['V = m/ρ'], answer: '0,002 м³ (2 дм³).' },
  { number: '17', page: 19, condition: '1. Определите давление на глубине 0,6 м в воде, керосине, ртути. 2. Вычислите давление воды на', steps: ['ρ = m/V = 712/80 = 8,9 г/см³.'], formulas: ['ρ = m/V'], answer: 'ρ = 8,9 г/см³.' },
  { number: '21', page: 21, condition: '1. На рисунке 131 изображён водяной барометр, созданный Паскалем в 1646 г. Какой высоты был столб', steps: ['V = m/ρ = 3/2700 ≈ 0,00111 м³ ≈ 1,11 дм³.'], formulas: ['V = m/ρ'], answer: '≈ 0,00111 м³ ≈ 1,11 л.' },
  { number: '56', page: 36, condition: 'Груз массой 5 кг движется по горизонтальной поверхности. Найдите силу тяжести, действующую на него.', steps: ['Сила тяжести: F = m · g.', 'g = 10 Н/кг.', 'F = 5 · 10 = 50 Н.'], formulas: ['F = mg'], answer: '50 Н.' },
  { number: '60', page: 38, condition: 'Пружина деформировалась на 4 см под действием силы 12 Н. Найдите жёсткость пружины.', steps: ['Закон Гука: F = k · x.', 'k = F / x = 12 Н / 0,04 м = 300 Н/м.'], formulas: ['F = kx, k = F/x'], answer: '300 Н/м.' },
  { number: '65', page: 40, condition: 'Груз покоится на горизонтальном столе. Масса груза 3 кг. Чему равна сила реакции опоры?', steps: ['Груз в покое — сумма сил равна нулю.', 'Сила тяжести: F = 3 · 10 = 30 Н (вниз).', 'По третьему закону Ньютона сила реакции опоры N = 30 Н (вверх).'], answer: '30 Н.' },
  { number: '70', page: 43, condition: 'Сила трения 8 Н действует на тело массой 4 кг. Найдите коэффициент трения скольжения, если N = 40 Н.', steps: ['μ = F_тр / N.', 'μ = 8 / 40 = 0,2.'], formulas: ['μ = Fтр/N'], answer: 'μ = 0,2.' },
  { number: '75', page: 46, condition: 'Первый закон Ньютона. Сформулируйте и приведите пример.', steps: ['Тело сохраняет состояние покоя или равномерного прямолинейного движения, если на него не действуют силы (или они уравновешены).', 'Пример: мяч катится по льду долго, т.к. трение мало.'], answer: 'Тело в покое или равномерно движется, если сумма сил = 0. Пример: мяч на гладком льду.' },
  { number: '80', page: 48, condition: 'Второй закон Ньютона. Найдите ускорение тела массой 4 кг под действием силы 20 Н.', steps: ['F = ma → a = F/m = 20/4 = 5 м/с².'], formulas: ['a = F/m'], answer: 'a = 5 м/с².' },
  { number: '85', page: 50, condition: 'Третий закон Ньютона. Книга лежит на столе. Опишите пару сил.', steps: ['Книга давит на стол с силой F (вниз).', 'По 3-му закону стол давит на книгу с силой N = F (вверх).'], answer: 'Действие и противодействие равны и противоположны по направлению.' },
  { number: '90', page: 52, condition: 'Сила тяжести действует на мяч массой 0,2 кг. Найдите эту силу.', steps: ['F = m·g = 0,2·10 = 2 Н.'], formulas: ['F = mg'], answer: '2 Н.' },
  { number: '151', page: 81, condition: 'Найдите давление, которое оказывает кирпич массой 3 кг на площадь 200 см².', steps: ['P = F / S.', 'F = m · g = 3 · 10 = 30 Н.', 'S = 200 см² = 0,02 м².', 'P = 30 / 0,02 = 1500 Па.'], formulas: ['P = F/S'], answer: '1500 Па.' },
  { number: '160', page: 85, condition: 'На какой глубине давление воды составляет 29 400 Па? (ρ = 1000 кг/м³, g = 10 Н/кг)', steps: ['P = ρ · g · h.', 'h = P / (ρ · g) = 29400 / (1000 · 10) = 2,94 м.'], formulas: ['P = ρgh'], answer: '≈ 2,94 м.' },
  { number: '170', page: 91, condition: 'Тело объёмом 0,5 дм³ полностью погружено в воду. Найдите выталкивающую силу.', steps: ['Сила Архимеда: F_A = ρ_жидк · g · V.', 'F_A = 1000 · 10 · 0,0005 = 5 Н.'], formulas: ['FA = ρgV'], answer: '5 Н.' },
  { number: '175', page: 93, condition: 'Атмосферное давление 101 325 Па. Переведите в мм рт. ст.', steps: ['101 325 Па ≈ 760 мм рт. ст.'], answer: '760 мм рт. ст. (стандартная атмосфера).' },
  { number: '180', page: 96, condition: 'Объясните закон Паскаля. Приведите пример.', steps: ['Давление, производимое на жидкость или газ, передаётся одинаково во всех направлениях.', 'Пример: гидравлический пресс, тормозная система автомобиля.'], answer: 'Давление в жидкости передаётся равномерно во все стороны (гидравлический пресс).' },
  { number: '236', page: 121, condition: 'Найдите работу, совершённую при подъёме тела массой 10 кг на высоту 3 м.', steps: ['A = F · s.', 'F = m · g = 10 · 10 = 100 Н.', 'A = 100 · 3 = 300 Дж.'], formulas: ['A = Fs = mgh'], answer: '300 Дж.' },
  { number: '245', page: 125, condition: 'Мощность мотора 500 Вт, время работы 10 с. Найдите совершённую работу.', steps: ['N = A / t, следовательно A = N · t.', 'A = 500 · 10 = 5000 Дж.'], formulas: ['A = Nt'], answer: '5000 Дж.' },
  { number: '255', page: 130, condition: 'Тело массой 5 кг подняли на высоту 4 м. Найдите его потенциальную энергию.', steps: ['E_п = m · g · h.', 'E_п = 5 · 10 · 4 = 200 Дж.'], formulas: ['Eп = mgh'], answer: '200 Дж.' },
  { number: '260', page: 133, condition: 'Подъёмный кран поднял груз 500 кг на 8 м. Найдите работу.', steps: ['A = mgh = 500·10·8 = 40 000 Дж = 40 кДж.'], formulas: ['A = mgh'], answer: '40 000 Дж = 40 кДж.' },
  { number: '265', page: 135, condition: 'Мотор мощностью 2 кВт работал 5 мин. Найдите работу.', steps: ['A = P·t = 2000·300 = 600 000 Дж = 600 кДж.'], formulas: ['A = Pt'], answer: '600 кДж.' },
  { number: '301', page: 153, condition: 'Рычаг в равновесии. Плечо одной силы 30 см, сила 60 Н. Второе плечо 20 см. Найдите вторую силу.', steps: ['Правило рычага: F₁ · l₁ = F₂ · l₂.', 'F₂ = F₁ · l₁ / l₂ = 60 · 30 / 20 = 90 Н.'], formulas: ['F₁l₁ = F₂l₂'], answer: '90 Н.' },
  { number: '310', page: 157, condition: 'Полезная работа механизма 800 Дж, затраченная работа 1000 Дж. Найдите КПД.', steps: ['КПД = A_пол / A_затр · 100%.', 'КПД = 800 / 1000 · 100% = 80%.'], formulas: ['η = Aпол/Aзатр · 100%'], answer: '80%.' },
  { number: '315', page: 159, condition: 'Условие равновесия рычага: F₁ = 40 Н, l₁ = 60 см. Найдите F₂ при l₂ = 30 см.', steps: ['F₁·l₁ = F₂·l₂.', 'F₂ = 40·60/30 = 80 Н.'], formulas: ['F₁l₁ = F₂l₂'], answer: 'F₂ = 80 Н.' },
]
