const makarychev9Extra2: GdzProblem[  ] = [ { number: '32', page: 16, condition: '32. Сравните числа: а) 5√3 и З√5; в) 0,З√10 и 0,1√80; б) 0,1√4500 и √45; г) -4√0,2 и - √0,7.', steps: ['3x − 2x > 1 + 7 → x > 8.'], answer: 'x > 8.' },
  { number: '36', page: 18, condition: '36. Вычислите: а)27⁵ + 27⁴ __________; 9⁸ + 9⁷ + 9⁶ б) 16⁷ + 16⁶/8¹⁰ + 8⁹ + 8⁸ в) 4⁹⁵ + 4⁹⁴+ 4⁹³/21⋅(16²)²³', steps: ['2x > 6 → x > 3.', 'x < 10.', 'Ответ: 3 < x < 10.'], answer: '3 < x < 10.' },
  { number: '40', page: 20, condition: '40. В каких границах заключено число у, если: а) у = 6,5 ± 0,1; б) у = 1,27 ± 0,2?', steps: ['x² < 4 → |x| < 2 → −2 < x < 2.'], answer: '−2 < x < 2.' },
  { number: '103', page: 54, condition: '103. Докажите, что функция, заданная формулой у = f(x), является чётной, если: a) f(x) = 6 - 5х² + х⁴; б) f(x) = 5|х|.', steps: ['x_в = −b/(2a) = 6/2 = 3.', 'y_в = 9 − 18 + 5 = −4.', 'Вершина: (3, −4).'], answer: 'Вершина (3, −4).' },
  { number: '108', page: 56, condition: '108. Задайте формулой: а) чётную функцию; б) нечётную функцию; в) функцию, которая не является ни чётной, ни нечётной. Ответ обоснуйте.', steps: ['−x² + 2x + 3 = 0 → x² − 2x − 3 = 0.', 'D = 4 + 12 = 16. x = (2±4)/2.', 'x₁ = 3, x₂ = −1.'], answer: 'Пересекает ось x в точках (3, 0) и (−1, 0).' },
  { number: '172', page: 87, condition: '172. Постройте график функции y = ³ˣ⁻²⁄ₓ₋₂. Найдите нули функции и промежутки знакопостоянства.', steps: ['Из второго: y = 1 − x.', 'x² + 1 − x = 1 → x² − x = 0 → x(x−1) = 0.', 'x = 0: y = 1. x = 1: y = 0.'], answer: '(0, 1) и (1, 0).' },
  { number: '180', page: 91, condition: '180. Изобразите схематически график функции f(x) = kx + b и перечислите её свойства, если: a) k > 0, b > 0; б) k < 0, b < 0; в) k > 0, b < 0.', steps: ['Замена t = |x| ≥ 0: t² − 3t + 2 = 0.', 't = 1 или t = 2.', '|x| = 1 → x = ±1; |x| = 2 → x = ±2.'], answer: 'x = ±1, x = ±2.' },
  { number: '273', page: 139, condition: '273. Решите неравенство: а) 2х(3х - 1) > 4х² + 5х + 9; б) (5х + 7)(х - 2) < 21х² - 11х - 13.', steps: ['a₂₀ = 3 + 19·4 = 79.', 'S₂₀ = 20·(3+79)/2 = 20·82/2 = 820.'], formulas: ['Sₙ = n(a₁+aₙ)/2'], answer: '820.' },
  { number: '278', page: 141, condition: '278. Одна сторона прямоугольника на 7 см больше другой. Какой может быть меньшая сторона, если площадь прямоугольника не превосходит 60 см²?', steps: ['a₅ = a₁ + 4d → 17 = a₁ + 12 → a₁ = 5.'], answer: 'a₁ = 5.' },
  { number: '325', page: 162, condition: '325. Является ли число: а) √3 + √5 корнем биквадратного уравнения х⁴ - 6х² + 3 = 0; б) √5 + √2 корнем биквадратного уравнения х⁴ - 10х² + 23 = 0?', steps: ['S = a₁/(1−q) = 4/(1−1/2) = 4/(1/2) = 8.'], formulas: ['S = a₁/(1-q)'], answer: 'S = 8.' },
  { number: '332', page: 165, condition: '332. Найдите корни уравнения: а) x² = ⁷ˣ ⁻ ⁴⁄₄ₓ ₋ ₇; б) x² = ⁵ˣ ⁻ ³⁄₃ₓ ₋ ₅ .', steps: ['a₄ = a₁·q³ → 54 = a₁·27 → a₁ = 2.'], answer: 'a₁ = 2.' },
  { number: '360', page: 180, condition: '360. Покажите схематически, в каких координатных четвертях располагается график линейного уравнения: а) 5х - 8у = - 2; б) 5х + 8у = 2; в) Зх + 4у - 25; г) Зх + 12у = -20; д) 15х - 18 = 0; е) 10y + 5 = 0.', steps: ['4! = 24; 2! = 2.', '24/2 = 12.'], answer: '12.' } ]
