const merzlyak6Extra: GdzProblem[  ] = [ { number: '21', page: 14, condition: '21 Найдите число, кратное числам 9 и 11, которое больше 100. Сколько существует таких', steps: ['56 : 8 = 7 — без остатка.', 'Да, 8 является делителем 56.'], answer: 'Да.' },
  { number: '25', page: 16, condition: '25 При делении числа a на 7 получили остаток 4. Какому условию должно удовлетворять число b, чтобы сумма a + b была кратна', steps: ['1, 2, 3, 4, 6, 8, 12, 24.', 'Проверяем: 24:1=24, 24:2=12, 24:3=8, 24:4=6. Делители симметричны.'], answer: '1, 2, 3, 4, 6, 8, 12, 24.' },
  { number: '30', page: 18, condition: '30 К однозначному числу дописали одну цифру, в результате чего оно увеличилось в 41 раз. Какую', steps: ['315 : 5 = 63 — без остатка.', 'Да, 315 кратно 5.'], answer: 'Да, 315 кратно 5.' },
  { number: '65', page: 30, condition: '65 Сумма двух натуральных чисел равно 700. Первое из них оканчивается цифрой 7. Если ее', steps: ['18 = 2·3², 24 = 2³·3.', 'НОД = 2·3 = 6.'], answer: 'НОД(18, 24) = 6.' },
  { number: '70', page: 32, condition: '70 По состоянию на 2015 г. в России было 152 государственных природных заповедника и', steps: ['4 = 2², 6 = 2·3, 8 = 2³.', 'НОК = 2³·3 = 24.'], answer: 'НОК = 24.' },
  { number: '135', page: 60, condition: '135 Найдите значение степени: 1) 3^4; 2) 6^2; 3) 5^3; 4) 2^7; 5) 7^3; 6)', steps: ['Знаменатели одинаковы: (2+3)/7 = 5/7.'], answer: '5/7.' },
  { number: '140', page: 62, condition: '140 Найдите наибольший общий делитель чисел a и b: 1) a = 2 * 2 * 3 * 5 * 7 * 19 и b = 2 * 3 * 3 * 7 * 11 * 13; 2) a=2^3*3^2*7^3*11^2*19 и', steps: ['(5−2)/9 = 3/9 = 1/3.'], answer: '1/3.' },
  { number: '150', page: 66, condition: '150 Используя цифры 2, 3, 4, запишите все возможные двузначные числа (цифры в каждом двузначном', steps: ['НОК(3,4)=12. 1/3=4/12, 1/4=3/12.', '4/12+3/12 = 7/12.'], answer: '7/12.' },
  { number: '160', page: 70, condition: '160 Если к некоторому двузначному числу справа дописать нуль, то данное число увеличится на 432. Найдите это', steps: ['3/5 · 10/9 = 30/45 = 2/3.'], answer: '2/3.' },
  { number: '170', page: 74, condition: '170 Найдите наименьшее общее кратное знаменателей дробей: 1) 8/9 и 7/6 ; 2) 11/20 и', steps: ['4/7 · 7/2 = 28/14 = 2.'], answer: '2.' },
  { number: '215', page: 98, condition: '215 Найдите среди данных дробей равные между собой: 1) 44/56, 1/2, 5/10, 11/14, 16/32 ; 2) 5/4, 81/99, 27/33, 20/16, 35/28. Запишите соответствующие', steps: ['30% = 0,3. 200 · 0,3 = 60.'], answer: '60.' },
  { number: '220', page: 100, condition: '220 Какую часть прямого угла составляет угол, градусная мера которого равна: 1) 2°; 2) 15°; 3) 36°; 4) 75°; 5)', steps: ['Скидка = 500 · 0,15 = 75 руб.', 'К оплате: 500 − 75 = 425 руб.'], answer: '425 руб.' },
  { number: '225', page: 102, condition: '225 Сократите: 1) (4*5)/(25*6); 2) (8*13)/(39*2); 3) (3*38)/(19*27); 4) (2*3*4*5)/(4*5*6*7); 5) (6*7*8*9*10)/(7*9*11*12); 6) (3*16?8*3)/27 ; 7)', steps: ['x · 0,8 = 48. x = 48 : 0,8 = 60.'], answer: '60.' },
  { number: '285', page: 138, condition: '285 Собственная скорость теплохода составляет 20*2/7 км/ч, а скорость течения реки - 2*11/14 км/ч', steps: ['|−12| > |7|, знак берём от −12.', '−12 + 7 = −5.'], answer: '−5.' },
  { number: '290', page: 140, condition: '290 Решите уравнение: 1) (x+ 4/21)? 4/15= 16/35 ; 2) (x? 8/19)? 4/57= 2/3 ; 3) (x? 8/9)+ 3/8= 19/36 ; 4) 3*1/6?(x+1*1/12)= 1/4 ; 5)', steps: ['Минус на минус = плюс. 8·3 = 24.'], answer: '24.' },
  { number: '295', page: 142, condition: '295 Для приготовления 6*1/2 кг крема кулинар взял 3*8/15 кг молока, 7/12 кг какао и сахар. Сколько килограммов сахара взял кулинар для приготовления', steps: ['Плюс на минус = минус. 15:5=3. Ответ: −3.'], answer: '−3.' },
  { number: '300', page: 144, condition: '300 Золотов, Серебров, Платинов и Бриллиантов нашли клад. Золотову досталась 1/6 клада,', steps: ['Меняем знаки каждого слагаемого: −3a + 5b.'], answer: '−3a + 5b.' },
  { number: '305', page: 146, condition: '305 Елена и Мария могут вместе набрать на компьютере текст рукописи за 6 ч. Какую часть', steps: ['(5x−3x) + (−2y+y) = 2x − y.'], answer: '2x − y.' } ]

